import { Component, OnInit, inject } from '@angular/core';
import { Title, Meta } from '@angular/platform-browser';

@Component({
  selector: 'app-product-page',
  templateUrl: './product-page.component.html',
})
export class ProductPageComponent implements OnInit {
  private titleService = inject(Title);
  private metaService = inject(Meta);

  ngOnInit(): void {
    const product = { name: 'Widget Pro', description: 'The best widget for professionals.' };

    // Update <title>
    this.titleService.setTitle(`${product.name} | My Store`);

    // Add or update <meta name="description">
    this.metaService.updateTag({ name: 'description', content: product.description });

    // Open Graph tags for social sharing
    this.metaService.updateTag({ property: 'og:title', content: product.name });
    this.metaService.updateTag({ property: 'og:description', content: product.description });
    this.metaService.updateTag({ property: 'og:image', content: 'https://example.com/widget.jpg' });
  }
}

import { Injectable, inject } from '@angular/core';
import { Title, Meta } from '@angular/platform-browser';
import { Product } from './product.model';

@Injectable({ providedIn: 'root' })
export class ProductMetaService {
  private title = inject(Title);
  private meta = inject(Meta);

  setForProduct(product: Product, canonicalUrl: string): void {
    this.title.setTitle(`${product.name} — ${product.brand} | Acme Shop`);

    this.meta.updateTag({ name: 'description', content: product.shortDescription });
    this.meta.updateTag({ name: 'robots', content: product.inStock ? 'index, follow' : 'noindex' });

    this.meta.updateTag({ property: 'og:title', content: product.name });
    this.meta.updateTag({ property: 'og:description', content: product.shortDescription });
    this.meta.updateTag({ property: 'og:image', content: product.imageUrl });
    this.meta.updateTag({ property: 'og:url', content: canonicalUrl });
    this.meta.updateTag({ property: 'og:type', content: 'product' });

    // Remove duplicate canonical and add updated one
    this.meta.removeTag('name="canonical"');
    const link = document.createElement('link');
    link.setAttribute('rel', 'canonical');
    link.setAttribute('href', canonicalUrl);
    document.head.appendChild(link);
  }
}

// ❌ Wrong: addTag creates a NEW tag every time — navigating between
// routes causes multiple duplicate <meta name="description"> tags to accumulate
this.metaService.addTag({ name: 'description', content: 'New page description' });

// ✅ Correct: updateTag adds the tag if absent, updates it if present
this.metaService.updateTag({ name: 'description', content: 'New page description' });

